mapper.select:
SELECT PK AS pk, 카테고리ID AS categoryId, 대분류카테고리ID AS largeCategoryId, 중분류카테고리ID AS midCategoryId, 카테고리명칭 AS categoryName, 카테고리분류 AS categoryType FROM J_참여자관리_JOB_CATEGORY WHERE
카테고리ID IN ( SELECT DISTINCT 대분류카테고리ID FROM J_참여자관리_JOB_CATEGORY WHERE 카테고리분류 = 2 AND 카테고리명칭 IN
#{name}
)
OR (카테고리분류 = 2 AND 카테고리명칭 IN
#{name}
)
OR (카테고리분류 = 3 AND 중분류카테고리ID IN ( SELECT 카테고리ID FROM J_참여자관리_JOB_CATEGORY WHERE 카테고리분류 = 2 AND 카테고리명칭 IN
#{name}
)) ORDER BY 대분류카테고리ID ASC, 중분류카테고리ID ASC, 카테고리분류 ASC, 카테고리ID ASC
